import React from "react";

const LoginPage = () => {
  return (
    <div style={styles.container}>
      {/* Card */}
      <div style={styles.card}>
        {/* Tabs */}
        <div style={styles.tabs}>
          <span style={{ ...styles.tab, ...styles.activeTab }}>Login</span>
          <span style={styles.tab}>Register</span>
        </div>

        {/* Login Form */}
        <div style={styles.form}>
          <label>Email</label>
          <input type="email" placeholder="aarav.sharma@gmail.com" style={styles.input} />

          <label>Password</label>
          <input type="password" placeholder="****" style={styles.input} />

          <div style={styles.remember}>
            <input type="checkbox" defaultChecked />
            <span>Remember Me</span>
          </div>

          <button style={styles.button}>Login</button>

          <p style={styles.text}>
            Don’t have an account? <span style={styles.link}>Register</span>
          </p>
        </div>
      </div>

      {/* Right Side */}
      <div style={styles.side}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/3064/3064197.png"
          alt="secure"
          style={styles.image}
        />
        <h2>Secure Digital Will Access</h2>
        <p style={{ color: "gray" }}>Your data is securely stored</p>
      </div>
    </div>
  );
};

export default LoginPage;
